query:
DELETE FROM contacts WHERE enrichmentSource = 'llm' AND name IN (
  SELECT name FROM (
    SELECT name FROM contacts WHERE enrichmentSource = 'llm' 
    GROUP BY name HAVING COUNT(DISTINCT company) >= 3
  ) as dupes
);

